fn whilestat(ls: &mut LexState, state: &mut LuaState, line: i32) -> Result<(), LuaError> {
    // C: luaX_next(ls) — skip WHILE
    lex_next(ls, state)?;
    // C: whileinit = luaK_getlabel(fs)
